def gen(rng, size):
    n = max(1, min(size, 1200))
    arr = [rng.randint(-100, 100)]
    for _ in range(n - 1):
        arr.append(rng.randint(-100, 100) if rng.random() < 0.6 else None)
    while arr and arr[-1] is None:
        arr.pop()
    return [arr]

