class Solution:
    def widthOfBinaryTree(self, root):
        if root is None:
            return 0
        best = 0
        level = [(root, 0)]
        while level:
            best = max(best, level[-1][1] - level[0][1] + 1)
            nxt = []
            base = level[0][1]
            for node, idx in level:
                rel = idx - base
                if node.left:
                    nxt.append((node.left, 2 * rel))
                if node.right:
                    nxt.append((node.right, 2 * rel + 1))
            level = nxt
        return best

