class Solution:
    def widthOfBinaryTree(self, root):
        if root is None:
            return 0
        best = 0
        from collections import deque
        q = deque([(root, 0)])
        while q:
            n = len(q)
            first = q[0][1]
            last = first
            for _ in range(n):
                node, idx = q.popleft()
                last = idx
                if node.left:
                    q.append((node.left, 2 * idx))
                if node.right:
                    q.append((node.right, 2 * idx + 1))
            best = max(best, last - first + 1)
        return best

