var widthOfBinaryTree = function(root) {
    if (root === null) return 0;
    let best = 0;
    let level = [[root, 0n]];
    while (level.length) {
        const first = level[0][1];
        const last = level[level.length - 1][1];
        const w = last - first + 1n;
        if (w > BigInt(best)) best = Number(w);
        const nxt = [];
        const base = first;
        for (const [node, idx] of level) {
            const rel = idx - base;
            if (node.left) nxt.push([node.left, 2n * rel]);
            if (node.right) nxt.push([node.right, 2n * rel + 1n]);
        }
        level = nxt;
    }
    return best;
};
